namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
  return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
  return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
  Ca6k00363CustomTilingData tiling;
  const gert::StorageShape *x_shape = context->GetInputShape(0);
  tiling.n = x_shape->GetDim(0);
  tiling.c = x_shape->GetDim(1);
  tiling.h = x_shape->GetDim(2);
  tiling.w = x_shape->GetDim(3);

  const gert::RuntimeAttrs *attrs = context->GetAttrs();
  const int32_t *upscale_factor = attrs->GetAttrPointer<int32_t>(0);
  tiling.upscaleFactor = *upscale_factor;

  // Output shape: N, C * r^2, H/r, W/r
  int32_t out_c = tiling.c * tiling.upscaleFactor * tiling.upscaleFactor;
  int32_t out_h = tiling.h / tiling.upscaleFactor;
  int32_t out_w = tiling.w / tiling.upscaleFactor;
  tiling.totalLength = tiling.n * out_c * out_h * out_w;

  // Tiling: compute tile length based on UB budget (each element 4 bytes)
  // We need to copy a block of input and write to output. For simplicity, tile over output elements.
  uint32_t maxTile = UB_BUDGET_BYTES / 4;  // elements (float)
  maxTile = AlignDown(maxTile, ALIGN_ELEMS);
  if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
  if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

  uint32_t tileLen = maxTile;
  uint32_t totalLen = static_cast<uint32_t>(tiling.totalLength);
  if (totalLen < tileLen) {
    uint32_t aligned = AlignDown(totalLen, ALIGN_ELEMS);
    tileLen = (aligned > 0) ? aligned : totalLen;
  }

  tiling.tileLength = static_cast<int32_t>(tileLen);

  // block dim
  uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalLen, tileLen);
  uint32_t blockDim = numTiles;
  if (blockDim < 8u) blockDim = 8u;
  if (blockDim > 24u) blockDim = 24u;
  tiling.blockDim = static_cast<int32_t>(blockDim);

  context->SetBlockDim(tiling.blockDim);

  tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                      context->GetRawTilingData()->GetCapacity());
  context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

  size_t *currentWorkspace = context->GetWorkspaceSizes(1);
  currentWorkspace[0] = 0;
  return ge::GRAPH_SUCCESS;
}

