#include "ca6k_00363_custom_tiling.h"

using namespace AscendC;

constexpr int32_t BUFFER_NUM = 1;  // single buffer for stability

class KernelPixelUnshuffle {
public:
  __aicore__ inline KernelPixelUnshuffle() {}

  __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                              int32_t n, int32_t c, int32_t h, int32_t w,
                              int32_t upscaleFactor, int32_t totalLength,
                              int32_t tileLength) {
    n_ = n;
    c_ = c;
    h_ = h;
    w_ = w;
    r_ = upscaleFactor;
    totalLen_ = totalLength;
    tileLen_ = tileLength;

    xGm_.SetGlobalBuffer((__gm__ float *)x);
    yGm_.SetGlobalBuffer((__gm__ float *)y);

    pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
    pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
  }

  __aicore__ inline void Process() {
    if (totalLen_ == 0 || tileLen_ == 0) return;

    const uint32_t blockNum = GetBlockNum();
    const uint32_t blockIdx = GetBlockIdx();

    // grid-stride over output elements
    int32_t outC = c_ * r_ * r_;
    int32_t outH = h_ / r_;
    int32_t outW = w_ / r_;
    int32_t stride = blockNum * tileLen_;

    int32_t start = blockIdx * tileLen_;
    int32_t end = start + tileLen_;
    if (start >= totalLen_) return;

    // Process tiles sequentially
    int32_t offset = start;
    while (offset < totalLen_) {
      int32_t curLen = (offset + tileLen_ <= totalLen_) ? tileLen_ : (totalLen_ - offset);
      CopyIn(offset, curLen);
      Compute(offset, curLen, outC, outH, outW);
      CopyOut(offset, curLen);
      offset += stride;
      if (offset >= totalLen_) break;
    }
  }

private:
  __aicore__ inline void CopyIn(int32_t outOffset, int32_t len) {
    // For pixel unshuffle, we need to read scattered input elements.
    // We will compute the input coordinates for each output element and read them individually.
    // Since tile length is moderate, we can use a local loop to copy.
    LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
    for (int32_t i = 0; i < len; i++) {
      int32_t outIdx = outOffset + i;
      // output shape: [N, outC, outH, outW]
      int32_t n = outIdx / (outC * outH * outW);
      int32_t tmp = outIdx % (outC * outH * outW);
      int32_t oc = tmp / (outH * outW);
      int32_t oh = (tmp % (outH * outW)) / outW;
      int32_t ow = tmp % outW;
      // input shape: [N, C, H, W] with H = oh * r + ph, W = ow * r + pw
      int32_t ic = oc / (r_ * r_);
      int32_t pixel = oc % (r_ * r_);
      int32_t ph = pixel / r_;
      int32_t pw = pixel % r_;
      int32_t inIdx = n * (c_ * h_ * w_) + ic * (h_ * w_) + (oh * r_ + ph) * w_ + (ow * r_ + pw);
      xLocal(i) = xGm_.GetValue(inIdx);
    }
    inQueueX_.EnQue(xLocal);
  }

  __aicore__ inline void Compute(int32_t outOffset, int32_t len,
                                 int32_t outC, int32_t outH, int32_t outW) {
    LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
    LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
    // simple copy
    for (int32_t i = 0; i < len; i++) {
      yLocal(i) = xLocal(i);
    }
    outQueueY_.EnQue(yLocal);
    inQueueX_.FreeTensor(xLocal);
  }

  __aicore__ inline void CopyOut(int32_t outOffset, int32_t len) {
    LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
    for (int32_t i = 0; i < len; i++) {
      yGm_.SetValue(outOffset + i, yLocal(i));
    }
    outQueueY_.FreeTensor(yLocal);
  }

private:
  TPipe pipe_;
  TQue<TPosition::VECIN, BUFFER_NUM> inQueueX_;
  TQue<TPosition::VECOUT, BUFFER_NUM> outQueueY_;
  GlobalTensor<float> xGm_;
  GlobalTensor<float> yGm_;
  int32_t n_ {0};
  int32_t c_ {0};
  int32_t h_ {0};
  int32_t w_ {0};
  int32_t r_ {2};
  int32_t totalLen_ {0};
  int32_t tileLen_ {0};
};

